instructions:
## Set up SWR

### 1. Install SWR
```
npm install swr
```

### 2. Create a global fetcher
- SWR requires a fetcher function. Define a typed fetcher in `lib/fetcher.ts`:
  ```ts
  export async function fetcher<T>(url: string): Promise<T> {
    const res = await fetch(url);
    if (!res.ok) {
      const error = new Error('An error occurred while fetching the data.');
      // Attach extra info to the error
      (error as Error & { info?: unknown; status?: number }).info = await res.json().catch(() => null);
      (error as Error & { status?: number }).status = res.status;
      throw error;
    }
    return res.json();
  }
  ```

### 3. Configure SWR globally (optional)
- Use `SWRConfig` to set default options across your app. In `app/providers.tsx` (or a client wrapper):
  ```tsx
  'use client';

  import { SWRConfig } from 'swr';
  import { fetcher } from '@/lib/fetcher';

  export function Providers({ children }: { children: React.ReactNode }) {
    return (
      <SWRConfig
        value={{
          fetcher,
          revalidateOnFocus: true,
          revalidateOnReconnect: true,
          shouldRetryOnError: true,
          errorRetryCount: 3,
        }}
      >
        {children}
      </SWRConfig>
    );
  }
  ```
- With `fetcher` set globally, each `useSWR` call can omit the second argument.

### 4. Basic useSWR hook
- Create a client component that uses `useSWR`:
  ```tsx
  'use client';

  import useSWR from 'swr';

  type User = {
    id: number;
    name: string;
    email: string;
  };

  export function UserProfile({ userId }: { userId: number }) {
    const { data: user, error, isLoading } = useSWR<User>(`/api/users/${userId}`);

    if (isLoading) return <div>Loading...</div>;
    if (error) return <div>Error: {error.message}</div>;
    if (!user) return null;

    return (
      <div>
        <h1>{user.name}</h1>
        <p>{user.email}</p>
      </div>
    );
  }
  ```
- The URL string is the cache key. The same URL always returns the same cached data.

### 5. Conditional fetching
- Pass `null` as the key to prevent fetching until a condition is met:
  ```tsx
  const { data } = useSWR<User>(userId ? `/api/users/${userId}` : null);
  ```
- The hook will not fire until `userId` is truthy.

### 6. Mutations with useSWRMutation
- Use `useSWRMutation` for POST/PUT/DELETE requests:
  ```tsx
  'use client';

  import useSWRMutation from 'swr/mutation';

  type CreateUserArgs = { name: string; email: string };
  type User = { id: number; name: string; email: string };

  async function createUser(url: string, { arg }: { arg: CreateUserArgs }): Promise<User> {
    const res = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(arg),
    });
    if (!res.ok) throw new Error('Failed to create user');
    return res.json();
  }

  export function CreateUserForm() {
    const { trigger, isMutating, error } = useSWRMutation('/api/users', createUser);

    const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
      e.preventDefault();
      const form = e.currentTarget;
      await trigger({ name: form.username.value, email: form.email.value });
      form.reset();
    };

    return (
      <form onSubmit={handleSubmit}>
        <input name="username" placeholder="Name" required />
        <input name="email" type="email" placeholder="Email" required />
        <button type="submit" disabled={isMutating}>
          {isMutating ? 'Creating...' : 'Create User'}
        </button>
        {error && <p>Error: {error.message}</p>}
      </form>
    );
  }
  ```

### 7. Manual cache revalidation
- After a mutation, revalidate related keys to refresh stale data:
  ```tsx
  import useSWR, { useSWRConfig } from 'swr';
  import useSWRMutation from 'swr/mutation';

  export function UserActions({ userId }: { userId: number }) {
    const { mutate } = useSWRConfig();
    const { trigger } = useSWRMutation(`/api/users/${userId}`, deleteUser);

    const handleDelete = async () => {
      await trigger();
      // Revalidate the user list
      mutate('/api/users');
    };

    return <button onClick={handleDelete}>Delete</button>;
  }
  ```
- `mutate(key)` tells SWR to re-fetch the given cache key.
- Use `mutate(key, newData, { revalidate: false })` for optimistic updates.

### 8. Pagination with useSWR
- Implement cursor-based or page-based pagination:
  ```tsx
  'use client';

  import useSWR from 'swr';
  import { useState } from 'react';

  type PostsPage = { posts: { id: number; title: string }[]; nextPage: number | null };

  export function PaginatedPosts() {
    const [page, setPage] = useState(1);
    const { data, isLoading } = useSWR<PostsPage>(`/api/posts?page=${page}`);

    return (
      <div>
        {isLoading ? <div>Loading...</div> : data?.posts.map(p => <p key={p.id}>{p.title}</p>)}
        <button onClick={() => setPage(p => p - 1)} disabled={page === 1}>Previous</button>
        <button onClick={() => setPage(p => p + 1)} disabled={!data?.nextPage}>Next</button>
      </div>
    );
  }
  ```

### 9. Infinite scroll with useSWRInfinite
- For infinite-scroll lists:
  ```tsx
  'use client';

  import useSWRInfinite from 'swr/infinite';

  const PAGE_SIZE = 10;

  export function InfinitePostsList() {
    const { data, size, setSize, isLoading } = useSWRInfinite(
      (index) => `/api/posts?page=${index + 1}&limit=${PAGE_SIZE}`
    );

    const posts = data ? data.flatMap((d) => d.posts) : [];
    const isEmpty = data?.[0]?.posts.length === 0;
    const isReachingEnd = isEmpty || (data && data[data.length - 1]?.posts.length < PAGE_SIZE);

    return (
      <div>
        {posts.map((post) => <div key={post.id}>{post.title}</div>)}
        {isLoading && <div>Loading...</div>}
        {!isReachingEnd && (
          <button onClick={() => setSize(size + 1)}>Load more</button>
        )}
      </div>
    );
  }
  ```

### Common Errors
- **Data always `undefined` on first render** → This is expected — SWR returns `undefined` while loading. Check `isLoading` before rendering data-dependent UI.
- **`useSWR` fires on every render** → The key is a new object reference on each render. Use a stable string URL, not an inline object. For query params, build the URL string explicitly.
- **Old data showing after mutation** → You forgot to call `mutate(key)` after the mutation. Call it with the affected cache key to trigger revalidation.
- **`revalidateOnFocus` causing too many requests** → Disable it for data that rarely changes: `useSWR(key, fetcher, { revalidateOnFocus: false })`.
- **Fetch running in a Server Component** → `useSWR` is a client-side hook. Add `'use client'` to the file.
- **TypeScript error: `data` is `T | undefined`** → SWR's `data` is typed as `T | undefined` because it can be loading. Guard with `if (!data) return null` or use optional chaining.

### What NOT to do
- Do NOT use `useSWR` in a Server Component — it is a client-only hook. Use `fetch()` directly in Server Components for server-side data fetching.
- Do NOT pass a new object or array as the SWR key — it creates a new cache entry on every render. Always use a string key.
- Do NOT use SWR for mutations that change server state without calling `mutate()` afterwards — the cache will show stale data.
- Do NOT use both SWR and TanStack Query in the same project for the same purpose — pick one data-fetching library and be consistent.
- Do NOT fetch data on the server AND use `useSWR` for the same endpoint in the same component — decide where the data lives (server state vs client state).
- Do NOT disable `shouldRetryOnError` globally — transient network errors will leave users with permanent error states.
